CREATE TABLE recurring_agreements(id TEXT PRIMARY KEY,tenant_id TEXT NOT NULL,branch_id TEXT NOT NULL,counterparty_ref TEXT NOT NULL,counterparty_name TEXT NOT NULL,description TEXT NOT NULL,amount INTEGER NOT NULL CHECK(amount>0),day_of_month INTEGER NOT NULL CHECK(day_of_month BETWEEN 1 AND 28),next_run_on TEXT NOT NULL,active INTEGER NOT NULL DEFAULT 1,created_at TEXT NOT NULL,UNIQUE(tenant_id,counterparty_ref,description));
CREATE TABLE recurring_executions(id TEXT PRIMARY KEY,tenant_id TEXT NOT NULL,agreement_id TEXT NOT NULL REFERENCES recurring_agreements(id),scheduled_on TEXT NOT NULL,commercial_document_id TEXT NOT NULL,created_at TEXT NOT NULL,UNIQUE(tenant_id,agreement_id,scheduled_on));
